class Person(val name: String)
class BankTransaction(val person: Person, val amount: java.math.BigDecimal)
fun bad(name: String, amounts: List<java.math.BigDecimal>): List<BankTransaction> {
    val result = mutableListOf<BankTransaction>()
    for (amount in amounts) {
        val person = Person(name)
        result.add(BankTransaction(person, amount))
    }
    return result
}

class Person(val name: String)
class BankTransaction(val person: Person, val amount: java.math.BigDecimal)
fun bad(name: String, amounts: List<java.math.BigDecimal>): List<String> {
    val log = mutableListOf<String>()
    for (amount in amounts) {
        val person = Person(name)
        val tx = BankTransaction(person, java.math.BigDecimal.ZERO)
        log.add(tx.toString())
    }
    return log
}

class Person(val name: String)
class BankTransaction(val person: Person, val amount: java.math.BigDecimal)
fun bad(name: String, amounts: ArrayDeque<java.math.BigDecimal>): List<BankTransaction> {
    val result = mutableListOf<BankTransaction>()
    while (amounts.isNotEmpty()) {
        val person = Person(name)
        result.add(BankTransaction(person, amounts.removeFirst()))
    }
    return result
}

class Person(val name: String)
class BankTransaction(val person: Person, val amount: java.math.BigDecimal)
fun bad(name: String, amounts: ArrayDeque<java.math.BigDecimal>): List<BankTransaction> {
    val result = mutableListOf<BankTransaction>()
    do {
        val person = Person(name)
        result.add(BankTransaction(person, amounts.removeFirst()))
    } while (amounts.isNotEmpty())
    return result
}

