class Person(val name: String)
fun good(names: List<String>): List<Person> {
    val result = mutableListOf<Person>()
    for (name in names) {
        val normalized = name.trim().lowercase()
        result.add(Person(normalized))
    }
    return result
}

class Person(val name: String)
class BankTransaction(val person: Person, val amount: java.math.BigDecimal)
fun good(name: String, amounts: List<java.math.BigDecimal>): List<BankTransaction> {
    val person = Person(name)
    val result = mutableListOf<BankTransaction>()
    for (amount in amounts) {
        val tx = BankTransaction(person, amount)
        result.add(tx)
    }
    return result
}

class Person(val name: String)
class BankTransaction(val person: Person, val amount: java.math.BigDecimal)
fun good(entries: List<Pair<Person, java.math.BigDecimal>>): List<BankTransaction> {
    val result = mutableListOf<BankTransaction>()
    for ((person, amount) in entries) {
        val tx = BankTransaction(person, amount)
        result.add(tx)
    }
    return result
}

