class Widget(val label: String)
fun good(items: List<String>) {
    for (i in items.indices) {
        val elem = items[i]       // derived from loop var i
        val w = Widget(elem)      // elem is derived -- not a repeated identical object
    }
}

class Report(val title: String)
fun good(sections: Array<String>) {
    for (i in sections.indices) {
        val section = sections[i]
        val report = Report(section.trim())  // section (derived var) in args
    }
}

import java.io.File
abstract class FileWatcher(val dir: File) {
    abstract fun onEvent(path: String?)
}
fun good(watchDirs: List<File>) {
    for (dir in watchDirs) {
        val watcher = object : FileWatcher(dir) {
            override fun onEvent(path: String?) {
                if (path == "achievements.json") {
                    process(File(dir, "achievements.json"))
                }
            }
        }
        watcher.onEvent("test")
    }
}
fun process(file: File) {}
